import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Header from "./dashboard/Header";
import Card from "./dashboard/Card"; // Ensure Card is used for the stats section
import Activity from "./dashboard/Activity";
import Peers from "./dashboard/Peers";
import ProfileSettings from "./dashboard/profilesettings"; // Import ProfileSettings
import AccountManagement from "./dashboard/accountmanagement"; // Import AccountManagement

const Dashboard = () => {
  const navigate = useNavigate();
  const [sidebarVisible, setSidebarVisible] = useState(false); // Control sidebar visibility

  const toggleSidebar = () => {
    setSidebarVisible(!sidebarVisible); // Toggle sidebar visibility
  };

  return (
    <div className="dashboard">
      <Header />

      {/* Profile Icon */}
      <div className="profile-icon flex justify-end p-4">
        <button onClick={toggleSidebar} className="bg-blue-600 text-white p-4 rounded-full shadow-md hover:bg-blue-700 transition">
          <span className="text-2xl">👤</span>
        </button>
      </div>

      {/* Sidebar */}
      {sidebarVisible && (
        <div className="sidebar fixed top-0 left-0 h-full w-64 bg-gray-800 text-white p-4">
          <ul className="space-y-4">
            <li>
              <button
                onClick={() => navigate("/profile-settings")}
                className="w-full p-2 bg-blue-600 rounded-md hover:bg-blue-700 transition"
              >
                Profile Settings
              </button>
            </li>
            <li>
              <button
                onClick={() => navigate("/account-management")}
                className="w-full p-2 bg-blue-600 rounded-md hover:bg-blue-700 transition"
              >
                Account Management
              </button>
            </li>
            <li>
              <button
                onClick={() => navigate("/authentication")}
                className="w-full p-2 bg-blue-600 rounded-md hover:bg-blue-700 transition"
              >
                Authentication
              </button>
            </li>
            <li>
              <button
                onClick={() => navigate("/signout")}
                className="w-full p-2 bg-red-600 rounded-md hover:bg-red-700 transition"
              >
                Sign Out
              </button>
            </li>
          </ul>
        </div>
      )}

      {/* Stats Section */}
      <div className="stats grid grid-cols-2 md:grid-cols-4 gap-4 p-4">
        <Card title="Active Collaborations" count="3" icon="👥" />
        <Card title="Study Groups" count="2" icon="📖" />
        <Card title="Projects" count="4" icon="🎯" />
        <Card title="Queries Written" count="5" icon="📅" />
      </div>

      {/* Main Section */}
      <div className="main-section flex flex-col md:flex-row gap-4 p-4">
        <Activity />
        <Peers />
      </div>
    </div>
  );
};

export default Dashboard;
